import React, { useState, useEffect, useRef } from 'react';

function ProjectDemoPage({ onNavigateBack }) {
    const [scene, setScene] = useState(0); // 0:Intro, 1:Scan, 2:Analyze, 3:Optimize, 4:Result
    const [subText, setSubText] = useState('');
    const audioContextRef = useRef(null);
    const canvasRef = useRef(null);

    // --- Sound Synthesis (Reused & Enhanced) ---
    const playSound = (type) => {
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        }
        const ctx = audioContextRef.current;
        const t = ctx.currentTime;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        if (type === 'tick') {
            osc.frequency.setValueAtTime(1000, t);
            osc.frequency.exponentialRampToValueAtTime(3000, t + 0.05);
            gain.gain.setValueAtTime(0.05, t);
            gain.gain.exponentialRampToValueAtTime(0.001, t + 0.05);
            osc.start(t); osc.stop(t + 0.05);
        } else if (type === 'bass') {
            osc.frequency.setValueAtTime(100, t);
            osc.frequency.exponentialRampToValueAtTime(50, t + 0.5);
            osc.type = 'sawtooth';
            gain.gain.setValueAtTime(0.2, t);
            gain.gain.exponentialRampToValueAtTime(0.001, t + 0.5);
            osc.start(t); osc.stop(t + 0.5);
        } else if (type === 'success') {
            osc.type = 'sine';
            osc.frequency.setValueAtTime(400, t);
            osc.frequency.linearRampToValueAtTime(800, t + 0.2);
            gain.gain.setValueAtTime(0.1, t);
            gain.gain.exponentialRampToValueAtTime(0.001, t + 0.5);
            osc.start(t); osc.stop(t + 0.5);
        }

        osc.connect(gain);
        gain.connect(ctx.destination);
    };

    // --- Animation Sequence ---
    useEffect(() => {
        const sequence = async () => {
            // SCENE 0: INTRO
            playSound('bass');
            setSubText('INITIALIZING DEMO PROTOCOL...');
            await wait(2000);

            // SCENE 1: SCANNING
            setScene(1);
            setSubText('ACQUIRING TARGET SYSTEM...');
            playSound('tick');
            await wait(3000);

            // SCENE 2: ANALYSIS
            setScene(2);
            setSubText('DETECTING HIGH EMISISON VECTORS...');
            playSound('bass');
            await wait(3000);

            // SCENE 3: OPTIMIZE
            setScene(3);
            setSubText('RE-WRITING NEURAL WEIGHTS...');
            playSound('tick');
            await wait(3000);

            // SCENE 4: RESULT
            setScene(4);
            setSubText('SYSTEM OPTIMIZED. CO2 REDUCED BY 45%.');
            playSound('success');

            // Voiceover
            const utterance = new SpeechSynthesisUtterance("Demonstration Complete. Green AI Monitor Systems Optimized.");
            utterance.rate = 0.9; utterance.pitch = 0.8;
            window.speechSynthesis.speak(utterance);
        };

        sequence();
    }, []);

    const wait = (ms) => new Promise(resolve => setTimeout(resolve, ms));

    // --- Canvas Matrix Effect ---
    useEffect(() => {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;

        const columns = canvas.width / 20;
        const drops = Array(Math.floor(columns)).fill(1);

        const drawMatrix = () => {
            ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            ctx.fillStyle = '#0F0';
            ctx.font = '15px monospace';

            for (let i = 0; i < drops.length; i++) {
                const text = String.fromCharCode(0x30A0 + Math.random() * 96);
                ctx.fillText(text, i * 20, drops[i] * 20);
                if (drops[i] * 20 > canvas.height && Math.random() > 0.975) drops[i] = 0;
                drops[i]++;
            }
            requestAnimationFrame(drawMatrix);
        };
        drawMatrix();
    }, []);

    return (
        <div style={{
            position: 'fixed', top: 0, left: 0, width: '100%', height: '100vh',
            background: '#000', color: '#fff', zIndex: 9999, overflow: 'hidden',
            fontFamily: 'monospace'
        }}>
            <canvas ref={canvasRef} style={{ position: 'absolute', top: 0, left: 0, opacity: 0.2 }} />

            {/* EXIT BUTTON */}
            <button
                onClick={onNavigateBack}
                style={{
                    position: 'absolute', top: 30, right: 30, zIndex: 100,
                    background: 'transparent', border: '1px solid #fff', color: '#fff',
                    padding: '10px 20px', cursor: 'pointer', fontFamily: 'monospace'
                }}
            >
                [ EXIT DEMO ]
            </button>

            {/* MAIN CONTAINER */}
            <div style={{
                position: 'relative', zIndex: 10, width: '100%', height: '100%',
                display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center'
            }}>

                {/* --- SCENE 0: INTRO --- */}
                {scene === 0 && (
                    <div className="fade-in">
                        <h1 style={{ fontSize: '4rem', textShadow: '0 0 20px var(--robotic-blue)', color: 'var(--robotic-blue)' }}>GREEN AI MONITOR</h1>
                        <div style={{ width: '200px', height: '2px', background: '#fff', margin: '20px auto' }}></div>
                    </div>
                )}

                {/* --- SCENE 1: SCANNING --- */}
                {scene === 1 && (
                    <div className="fade-in" style={{ display: 'flex', gap: '50px' }}>
                        <div style={{ width: '200px', height: '200px', border: '2px dashed var(--accent-orange)', display: 'flex', alignItems: 'center', justifyContent: 'center', animation: 'spin 10s linear infinite' }}>
                            <div style={{ width: '80%', height: '80%', background: 'rgba(255, 165, 0, 0.2)', borderRadius: '50%' }}></div>
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
                            <div style={{ fontSize: '2rem', color: 'var(--accent-orange)' }}>SCANNING MODEL ARCHITECTURE</div>
                            <div style={{ width: '300px', height: '10px', background: '#333', marginTop: '10px' }}>
                                <div style={{ width: '100%', height: '100%', background: 'var(--accent-orange)', animation: 'progress 3s linear' }}></div>
                            </div>
                        </div>
                    </div>
                )}

                {/* --- SCENE 2: ANALYZE --- */}
                {scene === 2 && (
                    <div className="fade-in">
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px' }}>
                            {['EPOCHS: 50', 'BATCH: 256', 'FP32: ON'].map((item, i) => (
                                <div key={i} style={{
                                    padding: '20px', border: '1px solid var(--accent-magenta)',
                                    color: 'var(--accent-magenta)', fontSize: '1.5rem',
                                    animation: `pulse 0.5s infinite ${i * 0.2}s`
                                }}>
                                    ⚠ {item}
                                </div>
                            ))}
                        </div>
                        <h2 style={{ marginTop: '40px', color: 'var(--accent-magenta)' }}>INEFFICENCY DETECTED</h2>
                    </div>
                )}

                {/* --- SCENE 3: OPTIMIZE --- */}
                {scene === 3 && (
                    <div className="fade-in">
                        <div style={{ fontSize: '2rem', color: 'var(--robotic-blue)', marginBottom: '30px' }}>APPLYING OPTIMIZATIONS</div>
                        <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                            <div style={{ fontSize: '1.5rem', color: '#666', textDecoration: 'line-through' }}>1.2 kg CO2</div>
                            <div style={{ fontSize: '2rem' }}>→</div>
                            <div style={{ fontSize: '3rem', color: 'var(--success-green)', fontWeight: 'bold' }}>0.65 kg CO2</div>
                        </div>
                    </div>
                )}

                {/* --- SCENE 4: RESULT --- */}
                {scene === 4 && (
                    <div className="fade-in">
                        <div style={{
                            fontSize: '6rem', color: 'var(--success-green)',
                            border: '5px solid var(--success-green)', borderRadius: '50%',
                            width: '150px', height: '150px', display: 'flex', alignItems: 'center', justifyContent: 'center',
                            margin: '0 auto 30px'
                        }}>✓</div>
                        <h1 style={{ color: '#fff' }}>DEMO COMPLETE</h1>
                        <button onClick={() => setScene(0)} style={{ marginTop: '20px', padding: '10px 20px', background: '#333', color: '#fff', border: 'none', cursor: 'pointer' }}>REPLAY</button>
                    </div>
                )}

                {/* SUBTEXT Overlay */}
                <div style={{
                    position: 'absolute', bottom: '50px',
                    background: 'rgba(0,0,0,0.8)', padding: '10px 30px', border: '1px solid #fff',
                    fontSize: '1.2rem', color: '#0F0', letterSpacing: '2px'
                }}>
                    {'>'} {subText} <span className="blink">_</span>
                </div>
            </div>

            <style>{`
                .fade-in { animation: fadeIn 0.5s ease-out; }
                @keyframes fadeIn { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
                @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
                @keyframes progress { from { width: 0%; } to { width: 100%; } }
                @keyframes pulse { 0% { opacity: 0.5; } 50% { opacity: 1; } 100% { opacity: 0.5; } }
                .blink { animation: blink 1s infinite; }
                @keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }
            `}</style>
        </div>
    );
}

export default ProjectDemoPage;
